dtsPropsFor.Button:
/** Visual style. @default "default" */
variant?: "default" | "outline" | "ghost" | "destructive";
/** Control size. @default "md" */
size?: "sm" | "md" | "icon";
children?: React.ReactNode;
className?: string;
type?: "button" | "submit" | "reset";
disabled?: boolean;
onClick?: React.MouseEventHandler<HTMLButtonElement>;
/** Accepts all standard <button> HTML attributes. */

dtsPropsFor.Card:
/** Card body. Compose with the CardHeader, CardTitle, and CardContent
 *  subcomponents, which are also exported from this library. */
children?: React.ReactNode;
className?: string;

dtsPropsFor.Badge:
children?: React.ReactNode;
className?: string;
/** Inline styles (used by CategoryBadge for per-category color). */
style?: React.CSSProperties;

dtsPropsFor.Input:
type?: string;
placeholder?: string;
value?: string | number;
defaultValue?: string | number;
disabled?: boolean;
className?: string;
onChange?: React.ChangeEventHandler<HTMLInputElement>;
/** Accepts all standard <input> HTML attributes. */

dtsPropsFor.Select:
/** <option> elements. */
children?: React.ReactNode;
value?: string | number;
defaultValue?: string | number;
disabled?: boolean;
className?: string;
onChange?: React.ChangeEventHandler<HTMLSelectElement>;

dtsPropsFor.Progress:
/** Percent complete, 0–100 (clamped to range). */
value: number;
/** Class applied to the filled bar (e.g. a status color like bg-emerald-500). */
barClassName?: string;
/** Class applied to the track. */
className?: string;

dtsPropsFor.Spinner:
className?: string;
/** Note: a CenteredSpinner({ label?: string }) helper is also exported for
 *  full-width loading states. */

dtsPropsFor.MoneyText:
/** Signed integer minor units (cents). Negative = outflow/spending. */
cents: number;
/** ISO 4217 currency code. @default "USD" */
currency?: string;
/** Color positive green / negative red. @default false (neutral). */
colorize?: boolean;
className?: string;

dtsPropsFor.SpendingTrendChart:
/** Monthly spending-vs-income series (oldest first). Renders at 100% width,
 *  260px tall. */
data: Array<{
  /** Short month label, e.g. "Jun 26". */
  month: string;
  /** Spending magnitude for the month, in cents (positive). */
  spending_cents: number;
  /** Income for the month, in cents (positive). */
  income_cents: number;
}>;

dtsPropsFor.CategoryBreakdownChart:
/** Per-category spend slices for one month (donut). Empty array renders an
 *  "No spending this month yet." placeholder. */
data: Array<{
  category: string;
  /** Human label shown in the tooltip. */
  label: string;
  /** Slice magnitude in cents. */
  value_cents: number;
  /** Hex color for the slice. */
  color: string;
}>;
